class GoogleVisionApi {
  static const String _apiKey = String.fromEnvironment('GCV_API_KEY', defaultValue: '');

  static Future<Map<String, dynamic>> annotateImage({required Uint8List bytes}) async {
    if (_apiKey.isEmpty) {
      throw Exception('Google Cloud Vision API key missing. Provide via --dart-define=GCV_API_KEY=...');
    }

    final uri = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$_apiKey');

    final reqBody = {
      'requests': [
        {
          'image': {'content': base64Encode(bytes)},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'FACE_DETECTION', 'maxResults': 5},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
            {'type': 'LANDMARK_DETECTION', 'maxResults': 5},
            {'type': 'LOGO_DETECTION', 'maxResults': 5},
          ],
        }
      ]
    };

    final resp = await http.post(
      uri,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(reqBody),
    );

    final body = resp.body.isEmpty ? '{}' : resp.body;
    final decoded = jsonDecode(body);

    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw Exception('Vision API failed: HTTP ${resp.statusCode}\n$body');
    }

    if (decoded is Map<String, dynamic>) {
      return decoded;
    }
    return {'raw': decoded};
  }
}

class AwsS3V4Presign {
  static const String _accessKeyId = String.fromEnvironment('AWS_ACCESS_KEY_ID', defaultValue: '');
  static const String _secretAccessKey = String.fromEnvironment('AWS_SECRET_ACCESS_KEY', defaultValue: '');

  static String objectUrl({
    required String bucket,
    required String region,
    required String key,
  }) {
    final encodedKey = key.split('/').map(Uri.encodeComponent).join('/');
    if (region == 'us-east-1') {
      return 'https://$bucket.s3.amazonaws.com/$encodedKey';
    }
    return 'https://$bucket.s3.$region.amazonaws.com/$encodedKey';
  }

  static Future<String> presignedPutUrl({
    required String bucket,
    required String region,
    required String key,
    required String contentType,
    required DateTime utcNow,
    required Duration expires,
  }) async {
    if (_accessKeyId.isEmpty || _secretAccessKey.isEmpty) {
      throw Exception('AWS credentials missing. Provide via --dart-define=AWS_ACCESS_KEY_ID=... --dart-define=AWS_SECRET_ACCESS_KEY=...');
    }

    final host = region == 'us-east-1' ? '$bucket.s3.amazonaws.com' : '$bucket.s3.$region.amazonaws.com';
    final canonicalUri = '/${key.split('/').map(_awsUriEncodePathSegment).join('/')}';

    final amzDate = _formatAmzDate(utcNow);
    final dateStamp = _formatDateStamp(utcNow);
    final service = 's3';

    final algorithm = 'AWS4-HMAC-SHA256';
    final credentialScope = '$dateStamp/$region/$service/aws4_request';
    final credential = '$_accessKeyId/$credentialScope';

    final query = <String, String>{
      'X-Amz-Algorithm': algorithm,
      'X-Amz-Credential': _awsUriEncode(credential),
      'X-Amz-Date': amzDate,
      'X-Amz-Expires': expires.inSeconds.toString(),
      'X-Amz-SignedHeaders': 'content-type;host',
    };

    final canonicalQueryString = query.entries.map((e) => '${e.key}=${e.value}').join('&');

    final canonicalHeaders = 'content-type:$contentType\nhost:$host\n';
    final signedHeaders = 'content-type;host';
    final payloadHash = 'UNSIGNED-PAYLOAD';

    final canonicalRequest = [
      'PUT',
      canonicalUri,
      canonicalQueryString,
      canonicalHeaders,
      signedHeaders,
      payloadHash,
    ].join('\n');

    final stringToSign = [
      algorithm,
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(_secretAccessKey, dateStamp, region, service);
    final signature = _hmacSha256Hex(signingKey, utf8.encode(stringToSign));

    final fullQuery = '$canonicalQueryString&X-Amz-Signature=$signature';
    final url = 'https://$host$canonicalUri?$fullQuery';
    return url;
  }

  static String _formatAmzDate(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}T${two(dt.hour)}${two(dt.minute)}${two(dt.second)}Z';
  }

  static String _formatDateStamp(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}';
  }

  static String _awsUriEncode(String s) {
    return Uri.encodeQueryComponent(s)
        .replaceAll('%7E', '~')
        .replaceAll('+', '%20');
  }

  static String _awsUriEncodePathSegment(String s) {
    return Uri.encodeComponent(s).replaceAll('%7E', '~');
  }

  static List<int> _hmacSha256(List<int> key, List<int> data) {
    final h = Hmac(sha256, key);
    return h.convert(data).bytes;
  }

  static String _hmacSha256Hex(List<int> key, List<int> data) {
    final h = Hmac(sha256, key);
    return h.convert(data).toString();
  }

  static List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmacSha256(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = _hmacSha256(kDate, utf8.encode(regionName));
    final kService = _hmacSha256(kRegion, utf8.encode(serviceName));
    final kSigning = _hmacSha256(kService, utf8.encode('aws4_request'));
    return kSigning;
  }
